const crypto = require('crypto');
const state = crypto.randomBytes(32).toString('hex');
// Store in server-side session (NOT client-side)
req.session.oauthState = state;
// Include in authorization URL
const authUrl = `https://provider.com/oauth/authorize?client_id=${clientId}&redirect_uri=${redirectUri}&response_type=code&state=${state}`;

// Callback handler - validate state parameter
app.get('/callback', (req, res) => {
  if (!req.query.state || req.query.state !== req.session.oauthState) {
    return res.status(403).send('Invalid state parameter');
  }
  // Proceed with token exchange only if state matches
});
```
Use cryptographically secure random generation and server-side session storage. Validate state on every callback.

